const ids = [];
// Example: const ids = [["Tylor", "1a02UQZRhupn5234"], ["April", "bGgpNeYcBWVCdhAk"], ["Elaine", "hOppsrlQbSCyjjFw"]]; 

for(let token of canvas.tokens.controlled){
    if(token){
        if(token.actor){
            ids.push([token.actor.name, token.actor.id]);
        }
    }
}


if(ids.length < 1){
    ui.notifications.error('Please add the player names, followed by their ids in the ids array inside the macro code, or select some tokens.');
    return;
}

let html = "<table> <tr> <th> Name </th> <th> Beats </th> <th> Arc. Beats </th> </tr>";

ids.forEach((ele,index,array) => {
let actor = game.actors.get(ele[1]);
let progress = actor?.system.progress;
let beats = progress ? progress.reduce((acc, cur) => {

return cur.beats > 0 ? acc + cur.beats : acc;
}, 0) : "ERR";
beats += actor?.system.beats + actor?.system.experience*5;
let arcBeats = progress ? progress.reduce((acc, cur) => {

return cur.arcaneBeats > 0 ? acc + cur.arcaneBeats : acc;
}, 0) : "ERR";
arcBeats += actor?.system.arcaneBeats + actor?.system.arcaneExperience*5;

html += "<tr>"
+ "<td>" + ele[0] + "</td>"
+ "<td>" + beats + "</td>"
+ "<td>" + arcBeats + "</td>"
+ "</tr>"
});
html += "</table>";


const chatData = {
user: game.user._id,
type: CONST.CHAT_MESSAGE_TYPES.OTHER,
content: html,
flavor: "Experience Total"
};
ChatMessage.create(chatData);
